// // This module provides a 32-entry, 32-bit wide data memory module. It supports writing and reading operations based on control signals. The input address (A) selects the memory location, using only the lower bits (A[5:0]). Writing occurs on the falling edge of the clock (clk) when WE is high. The output (RD) reflects the data at the selected address.
module top_module(input [31:0] A,input [31:0] WD,input WE,output [31:0] RD,input clk);reg [31:0] mem [0:31]; 
 assign RD = mem[A[6:2]]; 
 always @(posedge clk) begin 
 if(WE)begin 
 mem[A[6:2]] <= WD; 
 end 
 end 
 endmodule
